import os
import subprocess
import sys
from pathlib import Path

_REPO = Path(__file__).resolve().parents[3]


def _run_guard_probe():
    r"""Import the REAL runtime_guard under HOME=/home/alice with a protected
    file under it, and report (1) the ~/-variant set and (2) whether the guard
    blocks a destructive op on the ~/-form. Runs in a clean subprocess so the
    module-level DATA_FILE_PATH binds to the synthetic HOME."""
    code = r"""
import ast, inspect, os, sys, json
sys.path.insert(0, os.path.join(os.environ["REPO"], "hooks", "lib"))
import runtime_guard as rg
variants = sorted(rg._config_or_ancestor_variants())
tilde = rg._home_tilde_variant("/home/alice/.config/claude/protected-runtime.json")
# Behavioral: a destructive rm of BOTH the ~/-form and the absolute non-root
# home form must be BLOCKED.
verdict_tilde = rg.evaluate("rm -f ~/.config/claude/protected-runtime.json")[0]
verdict_abs = rg.evaluate("rm -f /home/alice/.config/claude/protected-runtime.json")[0]
# Ancestor-dir protection (codex): the proper ancestor DIRECTORIES of the data
# file must be in the variant set AND a destructive op on the ~/-ancestor and the
# absolute-ancestor must BLOCK, on a NON-ROOT home (the _config_ancestor_dirs
# generic-tilde change). Use rm -rf of the ancestor dir.
verdict_anc_tilde = rg.evaluate("rm -rf ~/.config/claude")[0]
verdict_anc_abs = rg.evaluate("rm -rf /home/alice/.config/claude")[0]
# Source check: no /root-specific LITERAL remains in the EXECUTABLE body of the
# tilde generator (strip the docstring, which may mention /root in prose).
src = inspect.getsource(rg._home_tilde_variant)
tree = ast.parse(src)
fn = tree.body[0]
if (fn.body and isinstance(fn.body[0], ast.Expr)
        and isinstance(getattr(fn.body[0], "value", None), ast.Constant)):
    fn.body = fn.body[1:]            # drop the docstring node
exec_src = ast.unparse(fn)
print(json.dumps({
    "variants": variants,
    "tilde": tilde,
    "verdict_tilde": verdict_tilde,
    "verdict_abs": verdict_abs,
    "verdict_anc_tilde": verdict_anc_tilde,
    "verdict_anc_abs": verdict_anc_abs,
    "has_anc_claude_tilde": "~/.config/claude" in variants,
    "has_anc_config_tilde": "~/.config" in variants,
    "root_literal_in_exec_body": "/root" in exec_src,
}))
"""
    env = {
        "PATH": os.environ.get("PATH", "/usr/bin:/bin"),
        "LANG": "C",
        "HOME": "/home/alice",
        "REPO": str(_REPO),
        "CLAUDE_PROTECTED_RUNTIME_FILE": "/home/alice/.config/claude/protected-runtime.json",
    }
    return subprocess.run([sys.executable, "-c", code], env=env,
                          capture_output=True, text=True)


def test_AC_WS1_8():
    r"""
    GIVEN: hooks/lib/runtime_guard.py protected-path normalization (codex #4, verify by Read around the tilde-variant handling). BASELINE: it adds ~/ tilde variants only for paths under /root/..., so on a non-root home (/home/alice/...) the ~/relative protected-path variant may stop being generated.
    WHEN:  the guard normalizes a protected path on a non-root home
    THEN:  the tilde-variant generation is GENERIC: any path under the actual user home (Path.home() / $HOME) gets its ~/relative variant added, and ancestor stop-roots treat the real user home consistently — no /root-specific behavior remains
    """
    import json
    r = _run_guard_probe()
    assert r.returncode == 0, f"guard probe crashed: stdout={r.stdout!r} stderr={r.stderr!r}"
    data = json.loads(r.stdout.strip().splitlines()[-1])

    # The ~/relative variant IS generated for a path under a NON-ROOT $HOME.
    assert data["tilde"] == "~/.config/claude/protected-runtime.json", (
        f"generic ~/-variant not generated on a non-root home: {data['tilde']!r}")
    assert "~/.config/claude/protected-runtime.json" in data["variants"], (
        f"~/-variant missing from the protected variant set: {data['variants']}")

    # The guard PROTECTS the path written either way (tilde form + absolute form).
    assert data["verdict_tilde"] == "BLOCK", (
        f"destructive op on the ~/-form must be BLOCKED; got {data['verdict_tilde']}")
    assert data["verdict_abs"] == "BLOCK", (
        f"destructive op on the /home/alice absolute form must be BLOCKED; got {data['verdict_abs']}")

    # No /root-specific behavior remains in the tilde generator's executable body.
    assert data["root_literal_in_exec_body"] is False, (
        "a /root-specific literal still exists in _home_tilde_variant's executable body")
